import{_ as l,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"クイックスタート: Gatewayのインストール・設定・起動と最初のメッセージ送信、DMペアリング保護について理解する | Clawdbot チュートリアル","description":"本章では、Clawdbotの初回使用を順を追って説明します。インストール、設定、Gatewayの起動、最初のメッセージ送信、DMペアリング保護機能について解説します。","frontmatter":{"title":"クイックスタート: Gatewayのインストール・設定・起動と最初のメッセージ送信、DMペアリング保護について理解する | Clawdbot チュートリアル","sidebarTitle":"ゼロから始める","subtitle":"クイックスタート: インストールから最初のメッセージまで","description":"本章では、Clawdbotの初回使用を順を追って説明します。インストール、設定、Gatewayの起動、最初のメッセージ送信、DMペアリング保護機能について解説します。","tags":["入門","クイックスタート"],"prerequisite":[],"order":10},"headers":[],"relativePath":"ja/moltbot/moltbot/start/index.md","filePath":"ja/moltbot/moltbot/start/index.md"}'),e={name:"ja/moltbot/moltbot/start/index.md"};function r(n,a,o,p,h,g){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="クイックスタート-インストールから最初のメッセージまで" tabindex="-1">クイックスタート: インストールから最初のメッセージまで <a class="header-anchor" href="#クイックスタート-インストールから最初のメッセージまで" aria-label="Permalink to &quot;クイックスタート: インストールから最初のメッセージまで&quot;">​</a></h1><p>Clawdbotへようこそ！本章では、ゼロからClawdbotを使用するための完全なフローをご案内します。AIアシスタントを素早く体験したい方も、設定オプションを詳しく知りたい方も、ここに該当するチュートリアルがあります。</p><hr><h2 id="章の概要" tabindex="-1">章の概要 <a class="header-anchor" href="#章の概要" aria-label="Permalink to &quot;章の概要&quot;">​</a></h2><p>本章には5つのチュートリアルが含まれており、Clawdbotの完全な導入フローをカバーしています：ソフトウェアのインストール、AIモデルと通信チャンネルの設定、Gatewayデーモンの起動、最初のメッセージの送信、そしてデフォルトのセキュリティ保護機能についての理解。本章を完了すると、正常に動作するパーソナルAIアシスタントが手に入ります。</p><hr><h2 id="推奨学習パス" tabindex="-1">推奨学習パス <a class="header-anchor" href="#推奨学習パス" aria-label="Permalink to &quot;推奨学習パス&quot;">​</a></h2><p>以下の順序でチュートリアルを学習することをお勧めします：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;クイックスタート] --&gt; B[onboarding-wizard&lt;br&gt;ガイド付き設定]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;Gatewayの起動]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;最初のメッセージ送信]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DMペアリングとアクセス制御]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>学習順序の説明</strong>：</p><ol><li><strong>クイックスタート</strong>（必須）：基本的なインストールと設定を完了させ、これは後続のすべての学習の前提です</li><li><strong>ガイド付き設定</strong>（推奨）：ウィザードの各オプションを深く理解し、細かい設定を行いたいユーザーに適しています</li><li><strong>Gatewayの起動</strong>（必須）：Gatewayデーモンの起動と管理方法を学習します</li><li><strong>最初のメッセージ送信</strong>（必須）：設定が正しいか確認し、AIアシスタントの使用を開始します</li><li><strong>DMペアリングとアクセス制御</strong>（推奨）：デフォルトのセキュリティメカニズムを理解し、AIアシスタントを保護します</li></ol><div class="tip custom-block"><p class="custom-block-title">クイックチャンネル</p><p>素早く体験したいだけの場合は、「クイックスタート」と「Gatewayの起動」の2つのチュートリアルを学習するだけで、メッセージを直接送信できます。その他のチュートリアルは、必要に応じて後で学習できます。</p></div><hr><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本章を学習する前に、以下を確認してください：</p><ul><li><strong>Node.js</strong>: ≥ 22.12.0（<code>node -v</code> で確認）</li><li><strong>オペレーティングシステム</strong>: macOS / Linux / Windows (WSL2)</li><li><strong>パッケージマネージャー</strong>: npm / pnpm / bun</li><li><strong>AIモデルアカウント</strong>（推奨）： <ul><li>Anthropic Claudeアカウント（Pro/Maxサブスクリプション）、OAuthフロー対応</li><li>または、OpenAI / DeepSeek / OpenRouterなどのプロバイダーのAPI Keyを準備</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Windowsユーザーへの注意</p><p>Windowsでは、<strong>WSL2</strong>の使用を強く推奨します。理由：</p><ul><li>多くのチャンネルがローカルバイナリファイルに依存している</li><li>デーモン（launchd/systemd）はWindowsでは利用不可</li></ul></div><hr><h2 id="子ページナビゲーション" tabindex="-1">子ページナビゲーション <a class="header-anchor" href="#子ページナビゲーション" aria-label="Permalink to &quot;子ページナビゲーション&quot;">​</a></h2><h3 id="_1-クイックスタート-⭐-コアチュートリアル" tabindex="-1"><a href="./getting-started/">1. クイックスタート</a> ⭐ コアチュートリアル <a class="header-anchor" href="#_1-クイックスタート-⭐-コアチュートリアル" aria-label="Permalink to &quot;[1. クイックスタート](./getting-started/) ⭐ コアチュートリアル&quot;">​</a></h3><p><strong>学習後にできること</strong>：</p><ul><li>✅ お使いのデバイスにClawdbotをインストール</li><li>✅ AIモデル認証を設定（Anthropic / OpenAI / その他プロバイダー）</li><li>✅ Gatewayデーモンを起動</li><li>✅ WebChatまたは設定したチャンネルから最初のメッセージを送信</li></ul><p><strong>対象ユーザー</strong>：すべてのユーザー、必読チュートリアル</p><p><strong>予想所要時間</strong>：15-20分</p><p><strong>主な内容</strong>：</p><ul><li>npm/pnpm/bunを使用したClawdbotのインストール</li><li>onboardingウィザードを実行して基本的な設定を完了</li><li>Gatewayを起動し、状態を確認</li><li>CLIまたはチャンネルからテストメッセージを送信</li></ul><p><strong>前提条件</strong>：なし</p><hr><h3 id="_2-ガイド付き設定" tabindex="-1"><a href="./onboarding-wizard/">2. ガイド付き設定</a> <a class="header-anchor" href="#_2-ガイド付き設定" aria-label="Permalink to &quot;[2. ガイド付き設定](./onboarding-wizard/)&quot;">​</a></h3><p><strong>学習後にできること</strong>：</p><ul><li>✅ インタラクティブウィザードを使用して完全な設定を完了</li><li>✅ QuickStartモードとManualモードの違いを理解</li><li>✅ Gatewayネットワーク、認証、Tailscaleを設定</li><li>✅ AIモデルプロバイダーを設定（setup-tokenとAPI Key）</li><li>✅ 通信チャンネルを有効化（WhatsApp、Telegramなど）</li><li>✅ スキルパッケージをインストールおよび管理</li></ul><p><strong>対象ユーザー</strong>：細かい設定を行いたいユーザー、高度なオプションを知りたい方</p><p><strong>予想所要時間</strong>：20-30分</p><p><strong>主な内容</strong>：</p><ul><li>QuickStart vs Manualモードの選択</li><li>Gatewayネットワーク設定（ポート、バインディング、認証）</li><li>AIモデル認証方式（setup-token推奨）</li><li>通信チャンネル設定フロー</li><li>スキルシステムの紹介</li></ul><p><strong>前提条件</strong>：<a href="./getting-started/">クイックスタート</a></p><hr><h3 id="_3-gatewayの起動-⭐-コアチュートリアル" tabindex="-1"><a href="./gateway-startup/">3. Gatewayの起動</a> ⭐ コアチュートリアル <a class="header-anchor" href="#_3-gatewayの起動-⭐-コアチュートリアル" aria-label="Permalink to &quot;[3. Gatewayの起動](./gateway-startup/) ⭐ コアチュートリアル&quot;">​</a></h3><p><strong>学習後にできること</strong>：</p><ul><li>✅ コマンドラインを使用してGatewayフォアグラウンドプロセスを起動</li><li>✅ Gatewayをバックグラウンドデーモンとして設定（macOS LaunchAgent / Linux systemd / Windows Scheduled Task）</li><li>✅ 異なるバインディングモード（loopback / LAN / Tailnet）と認証方式を理解</li><li>✅ 開発モードと本番モードを切り替え</li><li>✅ <code>--force</code>を使用して占有されているポートを強制的に解放</li></ul><p><strong>対象ユーザー</strong>：すべてのユーザー、必読チュートリアル</p><p><strong>予想所要時間</strong>：15-20分</p><p><strong>主な内容</strong>：</p><ul><li>フォアグラウンドモード vs デーモンモード</li><li>バインディングモードの選択（loopback / LAN / Tailnet / Auto）</li><li>認証方式の設定（Token / Password / Tailscale Identity）</li><li>開発モード（<code>--dev</code>）と本番モード</li><li>サービス管理コマンド（install / start / stop / restart）</li><li>ポート競合の処理（<code>--force</code>）</li></ul><p><strong>前提条件</strong>：<a href="./onboarding-wizard/">ガイド付き設定</a></p><hr><h3 id="_4-最初のメッセージ送信-⭐-コアチュートリアル" tabindex="-1"><a href="./first-message/">4. 最初のメッセージ送信</a> ⭐ コアチュートリアル <a class="header-anchor" href="#_4-最初のメッセージ送信-⭐-コアチュートリアル" aria-label="Permalink to &quot;[4. 最初のメッセージ送信](./first-message/) ⭐ コアチュートリアル&quot;">​</a></h3><p><strong>学習後にできること</strong>：</p><ul><li>✅ WebChatインターフェースを通じてメッセージを送信</li><li>✅ 設定済みのチャンネル（WhatsApp / Telegram / Slackなど）を通じてAIアシスタントと会話</li><li>✅ メッセージルーティングとレスポンスフローを理解</li><li>✅ AIアシスタントを使用して基本的なタスクを実行（クエリ、要約、コード生成など）</li></ul><p><strong>対象ユーザー</strong>：すべてのユーザー、必読チュートリアル</p><p><strong>予想所要時間</strong>：10-15分</p><p><strong>主な内容</strong>：</p><ul><li>WebChatインターフェースの使用</li><li>各チャンネルのメッセージ送信方法</li><li>メッセージフォーマットと返信メカニズム</li><li>一般的なタスク例（情報クエリ、コード生成、テキスト要約）</li><li>デバッグとトラブルシューティング</li></ul><p><strong>前提条件</strong>：<a href="./gateway-startup/">Gatewayの起動</a></p><hr><h3 id="_5-dmペアリングとアクセス制御" tabindex="-1"><a href="./pairing-approval/">5. DMペアリングとアクセス制御</a> <a class="header-anchor" href="#_5-dmペアリングとアクセス制御" aria-label="Permalink to &quot;[5. DMペアリングとアクセス制御](./pairing-approval/)&quot;">​</a></h3><p><strong>学習後にできること</strong>：</p><ul><li>✅ デフォルトのDMペアリング保護メカニズムについて理解</li><li>✅ 不明な送信者からのペアリングリクエストを承認または拒否</li><li>✅ ホワイトリストとブラックリストを設定</li><li>✅ アクセス制御ポリシーを設定</li><li>✅ ペアリングモードとセキュリティのベストプラクティスを理解</li></ul><p><strong>対象ユーザー</strong>：セキュリティを重視するユーザー、推奨学習</p><p><strong>予想所要時間</strong>：10-15分</p><p><strong>主な内容</strong>：</p><ul><li>DMペアリングメカニズムの原理</li><li>ペアリングフローとユーザー体験</li><li>ホワイトリストとブラックリストの設定</li><li>アクセス制御ポリシーの設定</li><li>セキュリティのベストプラクティス</li></ul><p><strong>前提条件</strong>：<a href="./first-message/">最初のメッセージ送信</a></p><hr><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="q-すべてのチュートリアルを学習する必要がありますか" tabindex="-1">Q: すべてのチュートリアルを学習する必要がありますか？ <a class="header-anchor" href="#q-すべてのチュートリアルを学習する必要がありますか" aria-label="Permalink to &quot;Q: すべてのチュートリアルを学習する必要がありますか？&quot;">​</a></h3><p><strong>A</strong>: 必ずしもそうではありません。素早く導入したいだけの場合は、「クイックスタート」と「Gatewayの起動」の2つのコアチュートリアルを学習するだけで、Clawdbotの使用を開始できます。その他のチュートリアルは、必要に応じて随時学習できます。</p><h3 id="q-一部のチュートリアルをスキップすると影響がありますか" tabindex="-1">Q: 一部のチュートリアルをスキップすると影響がありますか？ <a class="header-anchor" href="#q-一部のチュートリアルをスキップすると影響がありますか" aria-label="Permalink to &quot;Q: 一部のチュートリアルをスキップすると影響がありますか？&quot;">​</a></h3><p><strong>A</strong>: ありません。各チュートリアルは独立していますが、「クイックスタート」はインストールと基本的な設定を含む基礎となるため、まず学習することをお勧めします。その他のチュートリアルは、ニーズに応じて選択的に学習できます。</p><h3 id="q-aiアシスタントにすでに慣れているので、基礎チュートリアルをスキップできますか" tabindex="-1">Q: AIアシスタントにすでに慣れているので、基礎チュートリアルをスキップできますか？ <a class="header-anchor" href="#q-aiアシスタントにすでに慣れているので、基礎チュートリアルをスキップできますか" aria-label="Permalink to &quot;Q: AIアシスタントにすでに慣れているので、基礎チュートリアルをスキップできますか？&quot;">​</a></h3><p><strong>A</strong>: はい、可能です。すでに同様のAIアシスタントツールに慣れている場合は、「クイックスタート」をスキップして、「ガイド付き設定」と「Gatewayの起動」から直接学習し、Clawdbot特有の設定と起動方法を理解できます。</p><h3 id="q-本章を学習し終わった後、何ができますか" tabindex="-1">Q: 本章を学習し終わった後、何ができますか？ <a class="header-anchor" href="#q-本章を学習し終わった後、何ができますか" aria-label="Permalink to &quot;Q: 本章を学習し終わった後、何ができますか？&quot;">​</a></h3><p><strong>A</strong>: 本章を完了すると、正常に動作するClawdbotシステムを持つことができ、以下が可能になります：</p><ul><li>WebChatまたは複数のチャンネルを通じてAIアシスタントと会話</li><li>AIに基本的なタスクを実行させる（情報クエリ、コード生成、テキスト要約など）</li><li>DMペアリングメカニズムを使用してセキュリティを保護</li><li>高度な機能（マルチチャンネル設定、ツールシステム、スキルプラットフォームなど）の学習を続ける</li></ul><hr><h2 id="次のステップガイド" tabindex="-1">次のステップガイド <a class="header-anchor" href="#次のステップガイド" aria-label="Permalink to &quot;次のステップガイド&quot;">​</a></h2><p>本章を完了した後は、以下の学習を続けることができます：</p><ul><li><strong><a href="./../../platforms/channels-overview/">マルチチャンネルシステム概要</a></strong>: Clawdbotがサポートするすべての通信チャンネルとその特徴について</li><li><strong><a href="./../../platforms/whatsapp/">WhatsAppチャンネル</a></strong>: WhatsAppチャンネルの設定と使用について深く学習</li><li><strong><a href="./../../platforms/telegram/">Telegramチャンネル</a></strong>: Telegramチャンネルの設定と使用について深く学習</li><li><strong><a href="./../../platforms/webchat/">WebChatインターフェース</a></strong>: 内蔵のWebChatインターフェース機能について</li></ul><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>使用ニーズに応じて、対応するチャンネルを選択して深く学習してください。特定のチャンネル（WhatsAppやTelegramなど）を主に使用する場合は、そのチャンネルの専門チュートリアルを優先的に学習できます。</p></div>`,79)])])}const u=l(e,[["render",r]]);export{c as __pageData,u as default};
